client_script:
let isSubmitting = false;

frappe.web_form.validate = async () => {
    
    if (isSubmitting) {
        frappe.msgprint("Already submitting... please wait");
        return false;
    }

    let user = frappe.web_form.get_value("user");
    let company = frappe.web_form.get_value("vendor");
    let quotation_id = frappe.web_form.get_value("employee_car_process_form");

    let form_name = "Car Contract Form";
    let contract_number = frappe.web_form.get_value("contract_number");
    let form_status = frappe.web_form.get_value("contract_signed");
    let form_document = frappe.web_form.get_value("upload_contract");
    let form_date = frappe.web_form.get_value("contract_start_date");

    if (!form_document) {
        frappe.msgprint("Please attach file before submitting");
        return false;
    }
    try {
        const urlObj = new URL(form_document, window.location.origin);
        form_document = urlObj.pathname;
    } catch (e) {
        console.warn("URL parse failed:", form_document);
    }

    if (!form_document.startsWith("/files/") && !form_document.startsWith("/private/files/")) {
        frappe.msgprint("Invalid file uploaded. Please re-upload.");
        return false;
    }
    
    isSubmitting = true;

    const btn = $(".web-form-actions .btn-primary");
    const originalText = btn.text();

    btn.prop("disabled", true);
    btn.text("Saving...");

    try {
        const r = await frappe.call({
            method: "alms_app.api.car_process.car_form_fill",
            type: "POST",
            args: { 
                user,
                company,
                quotation_id,
                form_name,
                form_status,
                form_document,
            }
        });

        if (!r.message || r.message.status !== "success") {
            frappe.msgprint({
                title: "Error",
                indicator: "red",
                message: r.message?.message || "Something went wrong"
            });
            return false;
        }

        return true;

    } catch (e) {
        frappe.msgprint({
            title: "Server Error",
            indicator: "red",
            message: "API failed. Please try again."
        });
        return false;
    }
};
